<?php require '_header.php'; $items=read_json('blogs'); $old=find_by_slug($items,$_GET['slug']??'') ?: ['title'=>'','slug'=>'','category'=>'','date'=>date('Y-m-d'),'image'=>'assets/svg/blog-portfolio.svg','summary'=>'','content'=>'']; if($_SERVER['REQUEST_METHOD']==='POST'){ verify_csrf(); $slug=$_POST['slug'] ?: slugify($_POST['title']); $image=upload_image('image_file', $_POST['image']??''); $item=['title'=>trim($_POST['title']),'slug'=>$slug,'category'=>trim($_POST['category']),'date'=>trim($_POST['date']),'image'=>$image,'summary'=>trim($_POST['summary']),'content'=>trim($_POST['content'])]; $items=array_values(array_filter($items,fn($x)=>$x['slug']!==($_POST['old_slug']??''))); $items[]=$item; write_json('blogs',$items); header('Location: blogs.php'); exit; } ?><h1><?= $old['title']?'Edit':'Add' ?> Blog</h1><form class="admin-form" method="post" enctype="multipart/form-data"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="old_slug" value="<?=e($old['slug'])?>"><label>Title<input name="title" value="<?=e($old['title'])?>" required></label><label>Slug<input name="slug" value="<?=e($old['slug'])?>"></label><label>Category<input name="category" value="<?=e($old['category'])?>"></label><label>Date<input name="date" value="<?=e($old['date'])?>"></label><label>Image path<input name="image" value="<?=e($old['image'])?>"></label><label>Upload image<input type="file" name="image_file"></label><label>Summary<textarea name="summary"><?=e($old['summary'])?></textarea></label><label>Content<textarea name="content" rows="12"><?=e($old['content'])?></textarea></label><button class="btn primary">Save Blog</button></form><?php require '_footer.php'; ?>
